var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"베일!!!","JPN":"ベイル！！！","ENG":"Vale!","TWN":"培麗！！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"들리면 어서 대답하게!","JPN":"聞こえているなら返事したまえ！","ENG":"Answer me if you can hear me, now!","TWN":"有聽到嗎？快回答我！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>…</color>","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"베일…?","JPN":"ベイル……？","ENG":"Vale…?","TWN":"培麗…？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"악몽을 꾼다고요?","JPN":"悪夢を見る？","ENG":"You've been having nightmares?","TWN":"你說你做惡夢？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"별일 아니니 걱정 마시게. 이런 경험은 익숙하니.","JPN":"大したことではないから心配はいらん。こういうのには慣れているゆえ。","ENG":"It's nothing worth fretting over. I've grown quite used to such things.","TWN":"這沒什麼，你不用擔心。我已經習慣做惡夢。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"잠에서 깰 때마다 숨이 갑갑하다면서요? 그게 어떻게 별일이 아녜요?","JPN":"目覚めるたびに息が苦しいんでしょう？　それのどこが大したことじゃないんですか。","ENG":"You said you wake up feeling like you can't breathe. How's that nothing worth fretting over?","TWN":"你不是說每次醒來都覺得呼吸困難？這怎麼會是沒什麼？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"똑같은 경험은 아니겠지만… 나도 악몽을 자주 꾸곤 했어요.","JPN":"まったく同じとは言えませんけど……私もよく悪夢に苛まれていました。","ENG":"It's not quite the same, but… I used to have nightmares too.","TWN":"雖然跟你的經歷不太一樣…但我以前也經常做惡夢。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"대학시절에 침식재난에 휘말렸는데, 그때 내가 미처 구하지 못한 친구들이 계속 꿈에 나오거든요.","JPN":"大学時代、侵食災害に巻き込まれて。あの時、助けられなかった友人たちが夢に出てくるんです。","ENG":"Back in college, I got caught up in a Corruption disaster. The friends I couldn't save back then… they still come back in my dreams.","TWN":"大學時遇到侵蝕災難，那時候我沒能救活的朋友們會一直在夢裡出現。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"마음이 편치 않았겠구려.","JPN":"それは大変な思いをしたな。","ENG":"That must weigh heavily on you.","TWN":"你心裡一定很不好受吧。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"안타깝지만 그대는 평범한 사람이지 않은가. 관리국조차 침식재난 같은 재앙으로부터 모두를 구할 순 없는 걸세.","JPN":"しかし、残念だがそなたは普通の人間だ。管理局ですら侵食災害のような災害からは万人を救うことなどできん。","ENG":"Yet you're only an ordinary human, Vale. Not even the Administration could save everyone from a Corruption disaster.","TWN":"雖然很遺憾，但你只是一個普通人。就連管理局也無法從侵蝕災難這種災難中拯救所有人。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그 말이 맞아요. 그래서 악몽을 꾼 날은 무작정 바이크를 타고 정처 없이 달리곤 하죠.","JPN":"その通りです。だから悪夢を見た日は、バイクに乗ってあてもなく走るんです。","ENG":"You're right. So whenever I wake from one of those nightmares, I just jump on my bike and ride with no destination in mind.","TWN":"你說得對。所以每次做惡夢，我都會騎著摩托車漫無目的地狂奔。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"거리의 바람을 쐬면 잠깐동안 숨통이 트이긴 하지만… 결국 내가 아무것도 할 수 없다는 무력감을 지울 순 없더라고요.","JPN":"街の風に当たると、少しの間気が楽になるけど……結局、私には何もできないという無力感を消し去ることはできないんですよね。","ENG":"The wind on the road clears my head for a while… But that helpless feeling always creeps back in.","TWN":"雖然吹著街上的風，暫時能喘口氣…但那種無能為力的無奈感，終究無法抹去。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"지울 수 없다면, 우리가 할 수 있는 일을 해보는 건 어떻겠소?","JPN":"消せないのなら、我らにできることをしたらどうだろうか。","ENG":"If we can't erase it… then why not do what we can, instead?","TWN":"如果無法抹去，那不如試著做我們能做的事如何？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"네…?","JPN":"え……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대는 어린 시절에 보던 봄꽃이 그립다고 했었지.","JPN":"そなたは幼少期に見た春の花が恋しいと言っていたな。","ENG":"You once told me you missed the spring blossoms you used to see as a child.","TWN":"你說你懷念小時候看過的春天花朵對吧。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아, 그런 얘기도 했었죠. 대정화전쟁 이후론 이젠 볼 수 없는 풍경이 되어버렸지만요.","JPN":"あ、そういう話もしましたね。大浄化戦争の後、二度と見られない景色になってしまったけど。","ENG":"Ah, I did say that. After the Grand Purification War, that kind of scenery just vanished.","TWN":"對欸，我跟你說過。不過大淨化戰爭後，就再也看不到了。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그렇다면 우리가 잃어버린 계절을 되찾아보는 걸세.","JPN":"それなら、失われた季節を我らの手で取り戻すのだ。","ENG":"Then perhaps, we might try bringing that lost season back.","TWN":"既然如此，我們就把那失落的季節找回來吧。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대는 챔버의 학자라네. 이미 지난 일을 돌이키진 못해도, 세상을 침식으로부터 좀 더 살기 좋은 곳으로 바꿀 순 있을 거야.","JPN":"そなたはチェンバーの学者である。起きてしまったことをなかったことにはできぬが、世界をより良くすることならできるはずだ。","ENG":"You're a scholar of Chamber, Vale. We cannot undo what's past, but we might yet make this world a better place, free of Corruption.","TWN":"你是強巴的學者。雖然無法挽回過去的事，但至少能讓這個世界變得更適合居住。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"하지만… 계절을 되찾는다니. 현실적으로 불가능하지 않나요?","JPN":"でも……季節を取り戻すって、現実的に無理じゃないですか？","ENG":"But… bringing back the seasons? Isn't that impossible?","TWN":"但是…找回季節？這在現實中是不可能的吧？"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이곳 챔버엔 무궁무진한 가능성이 있지.","JPN":"ここ、チェンバーは無限大の可能性を秘めている。","ENG":"Here in Chamber, there's no shortage of potential.","TWN":"強巴有著無窮無盡的可能性。"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"다 함께 머리를 맞댄다면 시도할 가치는 있지 않겠나?","JPN":"皆で力を合わせれば、試す価値はあるのではないか？","ENG":"If we all put our heads together, surely, it's worth the attempt.","TWN":"若大家集思廣益，這件事還是值得一試的吧？"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};